import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldCheck, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_OFFLINE"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ 
                ticker: t, 
                price: Math.floor(Math.random() * 2000) + 500, 
                change: 0.00 
            })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 12;
                return { 
                    ...s, 
                    price: parseFloat((s.price + move).toFixed(2)), 
                    change: parseFloat(move.toFixed(2)) 
                };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={viewportWrapper}>
            <div style={compactTerminal}>
                <header style={headerSection}>
                    <div style={navRow}>
                        <button 
                            onClick={() => navigate(1)} 
                            disabled={currentIndex === history.length - 1}
                            style={navBtn(currentIndex === history.length - 1)}
                        >
                            <ChevronLeft size={24}/> <span style={{fontSize: '1rem'}}>PREVIOUS</span>
                        </button>

                        <div style={nodeDisplay}>
                            <Box size={20} color="var(--accent-primary)" />
                            <span style={nodeTitle}>{activeNode ? activeNode.goal : 'CORE_SYNCING...'}</span>
                        </div>

                        <button 
                            onClick={() => navigate(-1)} 
                            disabled={currentIndex === 0}
                            style={navBtn(currentIndex === 0)}
                        >
                            <span style={{fontSize: '1rem'}}>NEXT</span> <ChevronRight size={24}/>
                        </button>
                    </div>

                    <div style={statusRow}>
                        <div style={statusBadge(isConnected)}>
                            <Activity size={18} /> {isConnected ? 'LIVE_STREAM_ACTIVE' : 'OFFLINE'}
                        </div>
                        {/* FIXED: Using riskBadge style definition */}
                        <div style={riskBadge}>
                            <ShieldCheck size={18} /> EXPOSURE: {activeNode?.risk_score || 0}%
                        </div>
                        <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                    </div>
                </header>

                <main style={scrollArea}>
                    <div style={gridStyle}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardHeader}>
                                    <span style={tickerName}>{stock.ticker}</span>
                                    <Zap size={22} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceContainer}>
                                    <span style={priceLabel}>LAST_TRADED_PRICE</span>
                                    <span style={priceText}>₹{stock.price.toLocaleString()}</span>
                                </div>
                                <div style={changeRow(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={22}/> : <TrendingDown size={22}/>}
                                    <span>{stock.change >= 0 ? '+' : ''}{stock.change}%</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </main>
            </div>
        </div>
    );
};

/* --- Visual Styles (Big Text + Theme Compatible) --- */
const viewportWrapper = { 
    height: 'calc(100vh - 80px)', 
    background: 'var(--bg-primary, #07080a)', 
    display: 'flex', 
    justifyContent: 'center', 
    padding: '30px', 
    boxSizing: 'border-box', 
    overflow: 'hidden' 
};

const compactTerminal = { 
    width: '100%', 
    maxWidth: '1300px', 
    height: '100%', 
    background: 'var(--nav-bg, #0a0b0e)', 
    borderRadius: '24px', 
    border: '2px solid var(--surface-border, #1a1d23)', 
    display: 'flex', 
    flexDirection: 'column', 
    overflow: 'hidden', 
    boxShadow: '0 20px 60px rgba(0,0,0,0.4)' 
};

const headerSection = { 
    padding: '1.5rem 2rem', 
    borderBottom: '2px solid var(--surface-border, #1a1d23)', 
    flexShrink: 0,
    background: 'var(--bg-secondary, rgba(255,255,255,0.02))'
};

const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.2rem' };

const navBtn = (dis) => ({ 
    background: 'none', 
    border: 'none', 
    color: dis ? 'var(--text-muted, #333)' : 'var(--accent-primary)', 
    cursor: dis ? 'default' : 'pointer', 
    fontWeight: 900, 
    display: 'flex', 
    alignItems: 'center', 
    gap: '8px', 
    opacity: dis ? 0.3 : 1 
});

const nodeDisplay = { 
    display: 'flex', 
    alignItems: 'center', 
    gap: '15px', 
    background: 'var(--bg-input, #111318)', 
    padding: '10px 20px', 
    borderRadius: '10px', 
    border: '1px solid var(--surface-border, #1a1d23)' 
};

const nodeTitle = { fontSize: '1rem', fontWeight: 800, color: 'var(--text-primary, #fff)' };

const statusRow = { display: 'flex', gap: '2.5rem', alignItems: 'center' };

const statusBadge = (on) => ({ 
    display: 'flex', 
    alignItems: 'center', 
    gap: '8px', 
    fontSize: '0.8rem', 
    fontWeight: 900, 
    color: on ? '#10b981' : '#ef4444' 
});

const riskBadge = { 
    display: 'flex', 
    alignItems: 'center', 
    gap: '8px', 
    fontSize: '0.8rem', 
    fontWeight: 900, 
    color: 'var(--text-muted, #666)' 
};

const counterTag = { 
    marginLeft: 'auto', 
    fontSize: '0.8rem', 
    color: 'var(--accent-primary)', 
    background: 'rgba(16,185,129,0.1)', 
    padding: '4px 12px', 
    borderRadius: '6px' 
};

const scrollArea = { flex: 1, padding: '2.5rem', overflowY: 'auto' };

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '2rem' };

const stockCard = (up) => ({ 
    padding: '2rem', 
    background: 'var(--bg-input, #111318)', 
    border: '1px solid var(--surface-border, #1a1d23)', 
    borderRadius: '18px', 
    borderLeft: `6px solid ${up ? '#10b981' : '#ef4444'}`,
    color: 'var(--text-primary, #fff)'
});

const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '1.2rem' };
const tickerName = { fontSize: '1.1rem', fontWeight: 900, color: 'var(--accent-primary)', fontFamily: 'monospace' };
const priceContainer = { display: 'flex', flexDirection: 'column', marginBottom: '1rem' };
const priceLabel = { fontSize: '0.65rem', color: 'var(--text-muted, #444)', fontWeight: 800 };
const priceText = { fontSize: '2.6rem', fontWeight: 900, color: 'var(--text-primary, #fff)', fontFamily: 'monospace' };
const changeRow = (up) => ({ color: up ? '#10b981' : '#ef4444', fontSize: '1.3rem', fontWeight: 900, display: 'flex', alignItems: 'center', gap: '10px' });

export default LiveMarketPage;
